sql:
SELECT COUNT(video_id) AS total_videos_encoding
FROM videos
WHERE resolution = '1080p' AND status = 'encoding';

external_knowledge:
- 'Troubled' refers to video formats with a high number of errors during encoding;
- 'Casting a shadow over their numerous attempts' means the error rate is high relative to the total number of attempts;
- 'At least 5 times' ensures that the results are statistically significant, avoiding skewing by formats with very few attempts.

sql:
SELECT AVG(file_size) AS avg_file_size
FROM videos
WHERE duration * 189 / 8 < file_size;

SELECT title, view_count
FROM videos
WHERE view_count > (SELECT AVG(view_count) FROM videos);

SELECT category, MAX(view_count) AS max_view_count
FROM videos
GROUP BY category;

SELECT AVG(file_size / duration) AS average_bitrate
FROM videos
WHERE status = 'Completed';

external_knowledge:
- 'surfaced to the top of the view count chart' refers to videos with the highest view counts;
- 'completed their journey' refers to videos with a status of 'completed';
- 'left a trace in the encoding logs' refers to videos that have corresponding entries in the encoding logs.
